/**
 * Handler 1: Token Budget Tracker
 *
 * Counts tokens consumed by loaded instructions. Warns when they approach
 * context budget limits. Shows which files eat the most tokens.
 */

import { logHook } from '../lib/common.js';
import { basename } from 'node:path';
import type { LoadedFile } from './types.js';
import { classifySource } from './classify-source.js';

const HOOK_NAME = 'instructions-loaded/token-budget';
const TOKEN_BUDGET_WARN_PCT = 15;
const ESTIMATED_CONTEXT_TOKENS = 1_000_000;

export function tokenBudgetTracker(filesLoaded: LoadedFile[], _contents: Map<string, string>): string | null {
  let totalBytes = 0;
  const fileSizes: Array<{ name: string; tokens: number; source: string }> = [];

  for (const f of filesLoaded) {
    const bytes = f.byte_size ?? 0;
    totalBytes += bytes;
    const estimatedTokens = Math.ceil(bytes / 4);
    const source = classifySource(f.path);
    fileSizes.push({ name: basename(f.path), tokens: estimatedTokens, source });
  }

  const totalTokens = Math.ceil(totalBytes / 4);
  const pct = (totalTokens / ESTIMATED_CONTEXT_TOKENS) * 100;

  logHook(HOOK_NAME, `Token budget: ${totalTokens} tokens (${pct.toFixed(1)}% of ${ESTIMATED_CONTEXT_TOKENS})`);

  if (pct < 1) return null;

  fileSizes.sort((a, b) => b.tokens - a.tokens);
  const top3 = fileSizes.slice(0, 3).map(f => `${f.name} (${f.tokens})`).join(', ');

  const parts = [`[Instruction Budget] ${totalTokens} tokens across ${filesLoaded.length} files (${pct.toFixed(1)}% of context). Largest: ${top3}`];

  if (pct > TOKEN_BUDGET_WARN_PCT) {
    parts.push(`WARNING: Instructions consume >${TOKEN_BUDGET_WARN_PCT}% of context window. Consider trimming or splitting large files.`);
  }

  return parts.join('. ');
}
